          "name": {}
        }
    },

    "query": {
        "function_score": {
            "script_score": {
                "script": "(1 + 5 * log(1 + doc['size_active'].value) )"
            },

            "query": {
                "query_string": {
                    "fields": [
                        "name"
                    ],
                    "query": "microsoft"
                }
            }

        }
    }
}
```

